-- ---------------------------------------------------------------------------
-- Narrative threats expansion
-- ---------------------------------------------------------------------------
INSERT INTO infoops_narrative_threats (
    id, title, description, origin_country, target_countries, platforms,
    status, threat_level, spread_velocity, reach_estimate,
    key_claims, counter_narratives, first_detected, last_updated, classification
) VALUES
    ('a1800000-0000-0000-0000-000000000004', 'Iranian Axis of Resistance Propaganda', 'Narrative ecosystem amplifying anti-US, anti-Israel, and anti-normalization messaging across state and proxy channels.', 'IRN', '["ISR","USA","SAU","ARE","GBR"]', '["STATE_MEDIA","SOCIAL_MEDIA","MESSAGING_APP"]', 'ACTIVE', 'HIGH', 0.740, 9800000, '["Resistance is the only path to liberation","US bases are legitimate military targets","Normalization with Israel is betrayal of Palestine"]', '["Diplomatic normalization can reduce escalation risk","Civilian targeting violates international humanitarian norms"]', '2023-10-01T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000005', 'DPRK Nuclear Sovereignty Narrative', 'State messaging framing sanctions and allied military drills as existential threats requiring expanded DPRK deterrence.', 'PRK', '["USA","KOR","JPN"]', '["STATE_MEDIA","NEWS_OUTLET"]', 'ACTIVE', 'MEDIUM', 0.620, 4200000, '["Nuclear deterrent guarantees sovereignty","US military exercises are invasion rehearsals","Sanctions are acts of war"]', '["Deterrence and diplomacy are not mutually exclusive","UN sanctions are tied to proliferation behavior"]', '2022-12-01T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000006', 'Indian Hindu Nationalist Amplification', 'Coordinated online messaging amplifying hyper-nationalist narratives in cross-border political disputes.', 'IND', '["PAK","BGD","GBR","CAN"]', '["SOCIAL_MEDIA","VIDEO_PLATFORM","MESSAGING_APP"]', 'ACTIVE', 'MEDIUM', 0.680, 8400000, '["Pakistan is a failed state harboring terrorism","Indian Muslims are well-treated","Western media is anti-India"]', '["Fact-based reporting should separate governance critiques from identity narratives"]', '2023-06-15T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000007', 'Turkish Neo-Ottoman Regional Narrative', 'Messaging framing Turkey as the central stabilizing and civilizational actor across nearby regions.', 'TUR', '["GRC","SYR","IRQ","FRA","DEU"]', '["STATE_MEDIA","SOCIAL_MEDIA","NEWS_OUTLET"]', 'ACTIVE', 'MEDIUM', 0.610, 6500000, '["Turkey is the natural leader of the Muslim world","Kurdish autonomy threatens regional stability","Europe is hostile to Islam"]', '["Regional security requires plural governance and de-escalation mechanisms"]', '2023-03-10T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000008', 'Saudi Vision 2030 Image Laundering', 'Narrative campaign emphasizing modernization achievements while minimizing governance criticism.', 'SAU', '["USA","GBR","FRA"]', '["SOCIAL_MEDIA","NEWS_OUTLET","VIDEO_PLATFORM"]', 'ACTIVE', 'LOW', 0.560, 5100000, '["Saudi Arabia is modernizing rapidly","Critics are funded by Qatar/Iran","MBS is a reformer"]', '["Governance reform claims require measurable rights and accountability outcomes"]', '2023-04-20T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000009', 'UAE Democratic Stability Narrative', 'Strategic messaging portraying governance centralization as a model for regional stability.', 'ARE', '["USA","GBR"]', '["SOCIAL_MEDIA","NEWS_OUTLET","FORUM"]', 'ACTIVE', 'LOW', 0.520, 3800000, '["UAE is a model of Middle Eastern stability","Political Islam is inherently destabilizing","Human rights criticism is politically motivated"]', '["Institutional resilience and rights protections are both required for long-term stability"]', '2023-08-05T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000010', 'Pakistani Kashmir Liberation Narrative', 'Messaging architecture focused on reframing Kashmir as unresolved decolonization under occupation.', 'PAK', '["IND","GBR","USA"]', '["STATE_MEDIA","SOCIAL_MEDIA","MESSAGING_APP"]', 'ACTIVE', 'MEDIUM', 0.670, 5900000, '["Kashmir is an occupied territory","India commits genocide in Kashmir","UN resolutions demand plebiscite"]', '["Escalatory framing increases cross-border instability and civilian harm"]', '2022-09-15T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000011', 'Belarusian Western Aggression Narrative', 'State campaign depicting opposition and neighboring states as coordinated regime-change actors.', 'BLR', '["POL","LTU","LVA","DEU"]', '["STATE_MEDIA","NEWS_OUTLET"]', 'ACTIVE', 'MEDIUM', 0.600, 4300000, '["Western neighbors are plotting regime change","NATO expansion threatens Belarusian sovereignty","Opposition is foreign-funded"]', '["Political dissent and external military posturing should be assessed independently"]', '2022-11-01T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000012', 'Chinese South China Sea Sovereignty', 'Narrative operation defending expansive maritime claims and delegitimizing external naval presence.', 'CHN', '["PHL","VNM","MYS","USA","JPN"]', '["STATE_MEDIA","SOCIAL_MEDIA","NEWS_OUTLET","FORUM"]', 'ACTIVE', 'HIGH', 0.790, 14500000, '["Nine-dash line is historical Chinese territory","Freedom of navigation patrols are provocations","ASEAN claimants lack legal standing"]', '["Maritime disputes should be handled through international legal frameworks"]', '2023-01-12T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000013', 'Russian Africa Anti-Colonial Narrative', 'Content operations framing Russia-linked forces as anti-colonial security alternatives in Africa.', 'RUS', '["MLI","BFA","NER","CAF","LBY"]', '["SOCIAL_MEDIA","STATE_MEDIA","MESSAGING_APP"]', 'ACTIVE', 'HIGH', 0.760, 10100000, '["France is a neo-colonial oppressor","Wagner/Africa Corps provides real security","Western democracy is cultural imperialism"]', '["Security partnerships should be evaluated by local outcomes and civilian protections"]', '2023-02-01T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000014', 'Iranian Nuclear Program Justification', 'State-aligned messaging emphasizing sovereign entitlement to peaceful nuclear capability.', 'IRN', '["USA","ISR","GBR","FRA","DEU"]', '["STATE_MEDIA","NEWS_OUTLET","SOCIAL_MEDIA"]', 'ACTIVE', 'HIGH', 0.730, 9000000, '["Iran''s nuclear program is peaceful","IAEA is a tool of Western imperialism","Nuclear technology is Iran''s sovereign right"]', '["Verification regimes reduce escalation and proliferation risk"]', '2023-05-08T00:00:00Z', now(), 'UNCLASS'),
    ('a1800000-0000-0000-0000-000000000015', 'Chinese Belt and Road Debt Counter-Narrative', 'Messaging strategy contesting debt-trap framing and recasting BRI outcomes as mutually beneficial.', 'CHN', '["LKA","KEN","PAK","ETH","MYS"]', '["STATE_MEDIA","NEWS_OUTLET","SOCIAL_MEDIA"]', 'ACTIVE', 'MEDIUM', 0.640, 7800000, '["Debt trap is a Western fabrication","BRI projects are mutually beneficial","Western infrastructure aid is conditional and exploitative"]', '["Infrastructure impact should be measured through transparent debt sustainability metrics"]', '2022-10-20T00:00:00Z', now(), 'UNCLASS')
ON CONFLICT (id) DO NOTHING;

