INSERT INTO infoops_influence_campaigns (
    id, name, description, attributed_actor, attribution_confidence,
    sponsoring_state, target_countries, target_demographics, platforms,
    status, campaign_objectives, estimated_budget_usd,
    linked_narrative_ids, classification
) VALUES
    ('b1800000-0000-0000-0000-000000000003', 'Endless Mayfly', 'IRGC-linked campaign focused on anti-normalization and anti-US messaging across Middle East information channels.', 'IRGC-linked entities', 'HIGH', 'IRN', '["USA","ISR","SAU","GBR"]', '["regional audiences","diaspora communities","policy observers"]', '["SOCIAL_MEDIA","STATE_MEDIA","NEWS_OUTLET"]', 'ACTIVE', '["Discredit Saudi-Israeli normalization","Undermine US Middle East credibility","Amplify anti-Zionist sentiment"]', 8000000, '["a1800000-0000-0000-0000-000000000004","a1800000-0000-0000-0000-000000000014"]', 'UNCLASS'),
    ('b1800000-0000-0000-0000-000000000004', 'Ghostwriter', 'GRU-linked campaign targeting NATO cohesion through forged narratives and synthetic media artifacts.', 'GRU Unit 26165 (Fancy Bear)', 'HIGH', 'RUS', '["POL","LTU","LVA","DEU"]', '["voters","journalists","civil servants"]', '["SOCIAL_MEDIA","NEWS_OUTLET","MESSAGING_APP"]', 'ACTIVE', '["Undermine NATO Eastern Flank solidarity","Discredit Baltic governments","Fabricate internal NATO dissent"]', 12000000, '["a1000000-0000-0000-0000-000000000003","a1800000-0000-0000-0000-000000000013"]', 'UNCLASS'),
    ('b1800000-0000-0000-0000-000000000005', 'Spamouflage Dragon', 'Coordinated CCP-aligned influence operation using large inauthentic account networks and AI-assisted messaging.', 'PLA Strategic Support Force', 'MEDIUM', 'CHN', '["USA","TWN","AUS","CAN"]', '["social media users","diaspora audiences","policy communities"]', '["VIDEO_PLATFORM","SOCIAL_MEDIA","STATE_MEDIA"]', 'ACTIVE', '["Promote CCP narratives on major platforms","Attack Chinese dissidents abroad","Discredit Uyghur genocide reporting"]', 35000000, '["a1000000-0000-0000-0000-000000000002","a1800000-0000-0000-0000-000000000012","a1800000-0000-0000-0000-000000000015"]', 'UNCLASS'),
    ('b1800000-0000-0000-0000-000000000006', 'DPRK Crypto-Propaganda Hybrid', 'Hybrid campaign combining illicit cyber finance operations with coordinated narrative influence activity.', 'Lazarus Group / RGB', 'MEDIUM', 'PRK', '["KOR","JPN","USA"]', '["crypto communities","Korean-language audiences","security researchers"]', '["SOCIAL_MEDIA","FORUM","MESSAGING_APP"]', 'ACTIVE', '["Fund regime through crypto theft","Spread pro-regime content","Discredit defector testimonies"]', 5000000, '["a1800000-0000-0000-0000-000000000005"]', 'UNCLASS'),
    ('b1800000-0000-0000-0000-000000000007', 'Operation Doppelganger', 'Clone-domain disinformation operation impersonating trusted media to inject fabricated war and policy narratives.', 'GRU / Structura', 'HIGH', 'RUS', '["DEU","FRA","USA","UKR","ISR"]', '["news consumers","swing voters","online political communities"]', '["NEWS_OUTLET","SOCIAL_MEDIA","FORUM"]', 'ACTIVE', '["Clone Western news sites with fabricated content","Undermine support for Ukraine","Amplify war fatigue narratives"]', 20000000, '["a1000000-0000-0000-0000-000000000001","a1000000-0000-0000-0000-000000000003"]', 'UNCLASS'),
    ('b1800000-0000-0000-0000-000000000008', 'Indian Chronicles', 'Networked influence project using proxy outlets and NGO fronts to shape regional narratives in multilateral forums.', 'Srivastava Group (linked to Indian intelligence)', 'MEDIUM', 'IND', '["PAK","CHN","FRA","DEU"]', '["policy elites","NGO observers","diaspora networks"]', '["NEWS_OUTLET","SOCIAL_MEDIA","FORUM"]', 'ACTIVE', '["Influence EU parliament views on Kashmir","Create fake NGOs in UN processes","Discredit Pakistan internationally"]', 3000000, '["a1800000-0000-0000-0000-000000000006","a1800000-0000-0000-0000-000000000010"]', 'UNCLASS'),
    ('b1800000-0000-0000-0000-000000000009', 'Turkish Troll Armies', 'State-adjacent social amplification networks focused on diaspora opinion shaping and criticism suppression.', 'AKP Social Media Operations', 'MEDIUM', 'TUR', '["GRC","FRA","DEU","NLD"]', '["diaspora populations","journalists","activists"]', '["SOCIAL_MEDIA","MESSAGING_APP","VIDEO_PLATFORM"]', 'ACTIVE', '["Suppress Kurdish media narratives","Amplify Erdogan image globally","Attack diaspora critics"]', 7000000, '["a1800000-0000-0000-0000-000000000007"]', 'UNCLASS'),
    ('b1800000-0000-0000-0000-000000000010', 'Saudi Electronic Flies', 'Online influence operation to improve state image and counter rights-based criticism narratives.', 'Saudi Center for International Communications', 'MEDIUM', 'SAU', '["USA","GBR","TUR","QAT"]', '["policy influencers","journalists","regional audiences"]', '["SOCIAL_MEDIA","NEWS_OUTLET","VIDEO_PLATFORM"]', 'ACTIVE', '["Rehabilitate MBS image post-Khashoggi","Counter Qatar/Turkey media","Suppress human rights criticism"]', 10000000, '["a1800000-0000-0000-0000-000000000008"]', 'UNCLASS')
ON CONFLICT (id) DO NOTHING;

