INSERT INTO infoops_attribution_assessments (
    id, subject, attributed_to, confidence, evidence_summary,
    supporting_indicators, dissenting_evidence, analyst_id, classification
) VALUES
    ('d1800000-0000-0000-0000-000000000001', 'Energy FUD hashtag bot network (4,200 accounts)', 'GRU Unit 54777 (72nd Special Service Center)', 'HIGH', 'IP and infrastructure overlap with known St. Petersburg influence infrastructure; posting cadence and translation artifacts match known Russian TTP patterns.', '["c1000000-0000-0000-0000-000000000001"]', '["Some engagement originated from opportunistic non-state amplifiers"]', NULL, 'UNCLASS'),
    ('d1800000-0000-0000-0000-000000000002', 'Cloned European news domains (Doppelganger)', 'Structura National Technology (GRU contractor)', 'HIGH', 'Domain registration and hosting traces align with previously attributed Structura infrastructure; corroborated by open-source investigative reporting.', '["c1800000-0000-0000-0000-000000000010"]', '["Limited operator OPSEC occasionally obscures direct personnel attribution"]', NULL, 'UNCLASS'),
    ('d1800000-0000-0000-0000-000000000003', 'Spamouflage YouTube/X network', 'PLA Strategic Support Force, Unit 61398', 'MEDIUM', 'Account creation timing clusters with PRC working-hour windows and synchronized narratives matching state media themes.', '["c1800000-0000-0000-0000-000000000005","c1800000-0000-0000-0000-000000000014"]', '["Some botnets may be contractor-operated rather than directly military-operated"]', NULL, 'UNCLASS'),
    ('d1800000-0000-0000-0000-000000000004', 'Endless Mayfly fabricated documents', 'IRGC Quds Force — cyber division', 'HIGH', 'Infrastructure overlap and targeting profile are consistent with known IRGC-aligned influence and cyber operations.', '["c1800000-0000-0000-0000-000000000006"]', '["Attribution to specific sub-unit remains partially inferential"]', NULL, 'UNCLASS'),
    ('d1800000-0000-0000-0000-000000000005', 'Indian Chronicles fake NGO/media network', 'Srivastava Group (New Delhi)', 'MEDIUM', 'Open-source investigations linked hundreds of affiliated outlets and NGO facades to a single organizational hub.', '["c1800000-0000-0000-0000-000000000011"]', '["Official state sponsorship remains publicly denied"]', NULL, 'UNCLASS')
ON CONFLICT (id) DO NOTHING;
